INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000904, 'single', '90009', '下列何者「不是」節省能源的做法？', '電冰箱溫度長時間設定在強冷或急 冷,影印機當15 分鐘無人使用時，自動進入省電模式,電視機勿背著窗 戶，並避免太陽直射,短程不開汽車，以儘量搭乘公車、騎單車或步行為 宜 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000905, 'single', '90009', '經濟部能源局的能源效率標示分為幾個等級？', '1,3,5,7 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000906, 'single', '90009', '溫室氣體排放量：指自排放源排出之各種溫室氣體量乘以各該物質溫暖化 潛勢所得之合計量，以', '氧化亞氮(N 2O),二氧化碳(CO2),甲烷(CH4),六氟化硫(SF6) 當量表示', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000907, 'single', '90009', '國家溫室氣體長期減量目標為中華民國139 年(西元2050 年)溫室氣體排放 量降為中華民國94 年溫室氣體排放量的百分之多少以下？', '20,30,40,50 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000908, 'single', '90009', '溫室氣體減量及管理法所稱主管機關，在中央為下列何單位？', '經濟部能 源局,環境部,國家發展委員會,衛生福利部 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000909, 'single', '90009', '溫室氣體減量及管理法中所稱：一單位之排放額度相當於允許排放多少的 二氧化碳當量', '1 公斤,1 立方米,1 公噸,1 公升 之二氧化碳當量', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000910, 'single', '90009', '下列何者「不是」全球暖化帶來的影響？', '洪水,熱浪,地震,旱 災 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000911, 'single', '90009', '下列何種方法無法減少二氧化碳？', '想吃多少儘量點，剩下可當廚餘回收,選購當地、當季食材，減少運輸碳足跡,多吃蔬菜，少吃肉,自備杯 筷，減少免洗用具垃圾量 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000912, 'single', '90009', '下列何者不會減少溫室氣體的排放？', '減少使用煤、石油等化石燃料,大量植樹造林，禁止亂砍亂伐,增高燃煤氣體排放的煙囪,開發太陽 能、水能等新能源 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000913, 'single', '90009', '關於綠色採購的敘述，下列何者錯誤？', '採購由回收材料所製造之物品,採購的產品對環境及人類健康有最小的傷害性,選購對環境傷害較少、 污染程度較低的產品,以精美包裝為主要首選 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000914, 'single', '90009', '一旦大氣中的二氧化碳含量增加，會引起那一種後果？', '溫室效應惡化,臭氧層破洞,冰期來臨,海平面下降 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000915, 'single', '90009', '關於建築中常用的金屬玻璃帷幕牆，下列敘述何者正確？', '玻璃帷幕牆的 使用能節省室內空調使用,玻璃帷幕牆適用於臺灣，讓夏天的室內產生溫 暖的感覺,在溫度高的國家，建築物使用金屬玻璃帷幕會造成日照輻射 熱，產生室內「溫室效應」,臺灣的氣候濕熱，特別適合在大樓以金屬玻 璃帷幕作為建材 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000916, 'single', '90009', '下列何者不是能源之類型？', '電力,壓縮空氣,蒸汽,熱傳 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000917, 'single', '90009', '我國已制定能源管理系統標準為', 'CNS 50001,CNS 12681,CNS 14001,CNS 22000 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000918, 'single', '90009', '台灣電力股份有限公司所謂的三段式時間電價於夏月平日(非週六日)之尖 峰用電時段為何?', '9：00~16：00,9：00~24：00,6：00~11：00,16：00~22：00 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000919, 'single', '90009', '基於節能減碳的目標，下列何種光源發光效率最低，不鼓勵使用？', '白熾 燈泡,LED 燈泡,省電燈泡,螢光燈管 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000920, 'single', '90009', '下列的能源效率分級標示，哪一項較省電？', '1,2,3,4 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000921, 'single', '90009', '下列何者「不是」目前台灣主要的發電方式？', '燃煤,燃氣,水力,地 熱 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000922, 'single', '90009', '有關延長線及電線的使用，下列敘述何者錯誤？', '拔下延長線插頭時，應 手握插頭取下,使用中之延長線如有異味產生，屬正常現象不須理會,應避開火源，以免外覆塑膠熔解，致使用時造成短路,使用老舊之延長 線，容易造成短路、漏電或觸電等危險情形，應立即更換 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000923, 'single', '90009', '有關觸電的處理方式，下列敘述何者錯誤？', '立即將觸電者拉離現場,把電源開關關閉,通知救護人員,使用絕緣的裝備來移除電源 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000924, 'single', '90009', '目前電費單中，係以「度」為收費依據，請問下列何者為其單位？', 'kW,kWh,kJ,kJh ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000925, 'single', '90009', '依據台灣電力公司三段式時間電價(尖峰、半尖峰及離峰時段)的規定，請 問哪個時段電價最便宜？', '尖峰時段,夏月半尖峰時段,非夏月半尖峰 時段,離峰時段 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000926, 'single', '90009', '當用電設備遭遇電源不足或輸配電設備受限制時，導致用戶暫停或減少用 電的情形，常以下列何者名稱出現？', '停電,限電,斷電,配電 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000927, 'single', '90009', '照明控制可以達到節能與省電費的好處，下列何種方法最適合一般住宅社 區兼顧節能、經濟性與實際照明需求？', '加裝DALI 全自動控制系統,走廊與地下停車場選用紅外線感應控制電燈,全面調低照明需求,晚上 關閉所有公共區域的照明 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000928, 'single', '90009', '上班性質的商辦大樓為了降低尖峰時段用電，下列何者是錯的？', '使用儲 冰式空調系統減少白天空調用電需求,白天有陽光照明，所以白天可以將 照明設備全關掉,汰換老舊電梯馬達並使用變頻控制,電梯設定隔層停 止控制，減少頻繁啟動 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000929, 'single', '90009', '為了節能與降低電費的需求，應該如何正確選用家電產品？', '選用高功率 的產品效率較高,優先選用取得節能標章的產品,設備沒有壞，還是堪 用，繼續用，不會增加支出,選用能效分級數字較高的產品，效率較高， 5 級的比1 級的電器產品更省電 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000930, 'single', '90009', '有效而正確的節能從選購產品開始，就一般而言，下列的因素中，何者是 選購電氣設備的最優先考量項目？', '用電量消耗電功率是多少瓦攸關電費 支出，用電量小的優先,採購價格比較，便宜優先,安全第一，一定要 通過安規檢驗合格,名人或演藝明星推薦，應該口碑較好 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000931, 'single', '90009', '高效率燈具如果要降低眩光的不舒服，下列何者與降低刺眼眩光影響無 關？', '光源下方加裝擴散板或擴散膜,燈具的遮光板,光源的色溫,採 用間接照明 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000932, 'single', '90009', '用電熱爐煮火鍋，採用中溫50%加熱，比用高溫100%加熱，將同一鍋水 煮開，下列何者是對的？', '中溫50%加熱比較省電,高溫100%加熱比較 省電,中溫50%加熱，電流反而比較大,兩種方式用電量是一樣的 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000933, 'single', '90009', '電力公司為降低尖峰負載時段超載的停電風險，將尖峰時段電價費率(每度 電單價)提高，離峰時段的費率降低，引導用戶轉移部分負載至離峰時段， 這種電能管理策略稱為', '需量競價,時間電價,可停電力,表燈用戶彈 性電價 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000934, 'single', '90009', '集合式住宅的地下停車場需要維持通風良好的空氣品質，又要兼顧節能效 益，下列的排風扇控制方式何者是不恰當的？', '淘汰老舊排風扇，改裝取 得節能標章、適當容量的高效率風扇,兩天一次運轉通風扇就好了,結 合一氧化碳偵測器，自動啟動/停止控制,設定每天早晚二次定期啟動排 風扇 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000935, 'single', '90009', '大樓電梯為了節能及生活便利需求，可設定部分控制功能，下列何者是錯 誤或不正確的做法？', '加感應開關，無人時自動關閉電燈與通風扇,縮 短每次開門/關門的時間,電梯設定隔樓層停靠，減少頻繁啟動,電梯馬 達加裝變頻控制 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000936, 'single', '90009', '為了節能及兼顧冰箱的保溫效果，下列何者是錯誤或不正確的做法？', '冰 箱內上下層間不要塞滿，以利冷藏對流,食物存放位置紀錄清楚，一次拿 齊食物，減少開門次數,冰箱門的密封壓條如果鬆弛，無法緊密關門，應 儘速更新修復,冰箱內食物擺滿塞滿，效益最高 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000937, 'single', '90009', '電鍋剩飯持續保溫至隔天再食用，或剩飯先放冰箱冷藏，隔天用微波爐加 熱，就加熱及節能觀點來評比，下列何者是對的？', '持續保溫較省電,微波爐再加熱比較省電又方便,兩者一樣,優先選電鍋保溫方式，因為 馬上就可以吃 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000938, 'single', '90009', '不斷電系統UPS 與緊急發電機的裝置都是應付臨時性供電狀況；停電時， 下列的陳述何者是對的？', '緊急發電機會先啟動，不斷電系統UPS 是後 備的,不斷電系統UPS 先啟動，緊急發電機是後備的,兩者同時啟動,不斷電系統UPS 可以撐比較久 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000939, 'single', '90009', '下列何者為非再生能源？', '地熱能,焦煤,太陽能,水力能 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000940, 'single', '90009', '欲兼顧採光及降低經由玻璃部分侵入之熱負載，下列的改善方法何者錯 誤？', '加裝深色窗簾,裝設百葉窗,換裝雙層玻璃,貼隔熱反射膠 片 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000941, 'single', '90009', '一般桶裝瓦斯(液化石油氣)主要成分為丁烷與下列何種成分所組成？', '甲 烷,乙烷,丙烷,辛烷 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000942, 'single', '90009', '在正常操作，且提供相同暖氣之情形下，下列何種暖氣設備之能源效率最 高？', '冷暖氣機,電熱風扇,電熱輻射機,電暖爐 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000943, 'single', '90009', '下列何種熱水器所需能源費用最少？', '電熱水器,天然瓦斯熱水器,柴 油鍋爐熱水器,熱泵熱水器 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000944, 'single', '90009', '某公司希望能進行節能減碳，為地球盡點心力，以下何種作為並不恰當？', '將採購規定列入以下文字：「汰換設備時首先考慮能源效率1 級或具有 節能標章之產品」,盤查所有能源使用設備,實行能源管理,為考慮經 營成本，汰換設備時採買最便宜的機種 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000945, 'single', '90009', '冷氣外洩會造成能源之浪費，下列的入門設施與管理何者最耗能？', '全開 式有氣簾,全開式無氣簾,自動門有氣簾,自動門無氣簾 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000946, 'single', '90009', '下列何者「不是」潔淨能源？', '風能,地熱,太陽能,頁岩氣 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000947, 'single', '90009', '有關再生能源中的風力、太陽能的使用特性中，下列敘述中何者錯誤？', '間歇性能源，供應不穩定,不易受天氣影響,需較大的土地面積,設置 成本較高 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000948, 'single', '90009', '有關台灣能源發展所面臨的挑戰，下列選項何者是錯誤的？', '進口能源依 存度高，能源安全易受國際影響,化石能源所占比例高，溫室氣體減量壓 力大,自產能源充足，不需仰賴進口,能源密集度較先進國家仍有改善 空間 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000949, 'single', '90009', '若發生瓦斯外洩之情形，下列處理方法中錯誤的是？', '應先關閉瓦斯爐或 熱水器等開關,緩慢地打開門窗，讓瓦斯自然飄散,開啟電風扇，加強 空氣流動,在漏氣止住前，應保持警戒，嚴禁煙火 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000950, 'single', '90009', '全球暖化潛勢(Global Warming Potential, GWP)是衡量溫室氣體對全球暖 化的影響，其中是以何者為比較基準？', 'CO2,CH 4,SF 6,N2O ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000951, 'single', '90009', '有關建築之外殼節能設計，下列敘述中錯誤的是？', '開窗區域設置遮陽設 備,大開窗面避免設置於東西日曬方位,做好屋頂隔熱設施,宜採用全 面玻璃造型設計，以利自然採光 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000952, 'single', '90009', '下列何者燈泡的發光效率最高？', 'LED 燈泡,省電燈泡,白熾燈泡,鹵 素燈泡 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000953, 'single', '90009', '有關吹風機使用注意事項，下列敘述中錯誤的是？', '請勿在潮濕的地方使 用，以免觸電危險,應保持吹風機進、出風口之空氣流通，以免造成過熱,應避免長時間使用，使用時應保持適當的距離,可用來作為烘乾棉被及 床單等用途 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000954, 'single', '90009', '下列何者是造成聖嬰現象發生的主要原因？', '臭氧層破洞,溫室效應,霧霾,颱風 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000955, 'single', '90009', '為了避免漏電而危害生命安全，下列「不正確」的做法是？', '做好用電設 備金屬外殼的接地,有濕氣的用電場合，線路加裝漏電斷路器,加強定 期的漏電檢查及維護,使用保險絲來防止漏電的危險性 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000956, 'single', '90009', '用電設備的線路保護用電力熔絲(保險絲)經常燒斷，造成停電的不便，下 列「不正確」的作法是？', '換大一級或大兩級規格的保險絲或斷路器就不 會燒斷了,減少線路連接的電氣設備，降低用電量,重新設計線路，改 較粗的導線或用兩迴路並聯,提高用電設備的功率因數 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000957, 'single', '90009', '政府為推廣節能設備而補助民眾汰換老舊設備，下列何者的節電效益最 佳？', '將桌上檯燈光源由螢光燈換為LED 燈,優先淘汰10 年以上的老 舊冷氣機為能源效率標示分級中之一級冷氣機,汰換電風扇，改裝設能源 效率標示分級為一級的冷氣機,因為經費有限，選擇便宜的產品比較重 要 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000958, 'single', '90009', '依據我國現行國家標準規定，冷氣機的冷氣能力標示應以何種單位表示？', 'kW,BTU/h,kcal/h,RT ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000959, 'single', '90009', '漏電影響節電成效，並且影響用電安全，簡易的查修方法為', '電氣材料行 買支驗電起子，碰觸電氣設備的外殼，就可查出漏電與否,用手碰觸就可 以知道有無漏電,用三用電表檢查,看電費單有無紀錄 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000960, 'single', '90009', '使用了10 幾年的通風換氣扇老舊又骯髒，噪音又大，維修時採取下列哪 一種對策最為正確及節能？', '定期拆下來清洗油垢,不必再猶豫，10 年 以上的電扇效率偏低，直接換為高效率通風扇,直接噴沙拉脫清潔劑就可 以了，省錢又方便,高效率通風扇較貴，換同機型的廠內備用品就好 了 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000961, 'single', '90009', '電氣設備維修時，在關掉電源後，最好停留1 至5 分鐘才開始檢修，其主 要的理由為下列何者？', '先平靜心情，做好準備才動手,讓機器設備降 溫下來再查修,讓裡面的電容器有時間放電完畢，才安全,法規沒有規 定，這完全沒有必要 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000962, 'single', '90009', '電氣設備裝設於有潮濕水氣的環境時，最應該優先檢查及確認的措施是？', '有無在線路上裝設漏電斷路器,電氣設備上有無安全保險絲,有無過 載及過熱保護設備,有無可能傾倒及生鏽 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000963, 'single', '90009', '為保持中央空調主機效率，每隔多久時間應請維護廠商或保養人員檢視中 央空調主機？', '半年,1 年,1.5 年,2 年 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000964, 'single', '90009', '家庭用電最大宗來自於', '空調及照明,電腦,電視,吹風機 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000965, 'single', '90009', '冷氣房內為減少日照高溫及降低空調負載，下列何種處理方式是錯誤的？', '窗戶裝設窗簾或貼隔熱紙,將窗戶或門開啟，讓屋內外空氣自然對流,屋頂加裝隔熱材、高反射率塗料或噴水,於屋頂進行薄層綠化 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000966, 'single', '90009', '有關電冰箱放置位置的處理方式，下列何者是正確的？', '背後緊貼牆壁節 省空間,背後距離牆壁應有10 公分以上空間，以利散熱,室內空間有 限，側面緊貼牆壁就可以了,冰箱最好貼近流理台，以便存取食材 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000967, 'single', '90009', '下列何項「不是」照明節能改善需優先考量之因素？', '照明方式是否適當,燈具之外型是否美觀,照明之品質是否適當,照度是否適當 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000968, 'single', '90009', '醫院、飯店或宿舍之熱水系統耗能大，要設置熱水系統時，應優先選用何 種熱水系統較節能？', '電能熱水系統,熱泵熱水系統,瓦斯熱水系統,重油熱水系統 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000969, 'single', '90009', '如下圖，你知道這是什麼標章嗎？', '省水標章,環保標章,奈米標章,能源效率標示 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000970, 'single', '90009', '台灣電力公司電價表所指的夏月用電月份(電價比其他月份高)是為', '4/1~7/31,5/1~8/31,6/1~9/30,7/1~10/31 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000971, 'single', '90009', '屋頂隔熱可有效降低空調用電，下列何項措施較不適當？', '屋頂儲水隔熱,屋頂綠化,於適當位置設置太陽能板發電同時加以隔熱,鋪設隔熱 磚 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000972, 'single', '90009', '電腦機房使用時間長、耗電量大，下列何項措施對電腦機房之用電管理較 不適當？', '機房設定較低之溫度,設置冷熱通道,使用較高效率之空調 設備,使用新型高效能電腦設備 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000973, 'single', '90009', '下列有關省水標章的敘述中正確的是？', '省水標章是環境部為推動使用節 水器材，特別研定以作為消費者辨識省水產品的一種標誌,獲得省水標章 的產品並無嚴格測試，所以對消費者並無一定的保障,省水標章能激勵廠 商重視省水產品的研發與製造，進而達到推廣節水良性循環之目的,省水 標章除有用水設備外，亦可使用於冷氣或冰箱上 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000974, 'single', '90009', '透過淋浴習慣的改變就可以節約用水，以下的何種方式正確？', '淋浴時抹 肥皂，無需將蓮蓬頭暫時關上,等待熱水前流出的冷水可以用水桶接起來 再利用,淋浴流下的水不可以刷洗浴室地板,淋浴沖澡流下的水，可以 儲蓄洗菜使用 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000975, 'single', '90009', '家人洗澡時，一個接一個連續洗，也是一種有效的省水方式嗎？', '是，因 為可以節省等待熱水流出之前所先流失的冷水,否，這跟省水沒什麼關 係，不用這麼麻煩,否，因為等熱水時流出的水量不多,有可能省水也 可能不省水，無法定論 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000976, 'single', '90009', '下列何種方式有助於節省洗衣機的用水量？', '洗衣機洗滌的衣物盡量裝 滿，一次洗完,購買洗衣機時選購有省水標章的洗衣機，可有效節約用水,無需將衣物適當分類,洗濯衣物時盡量選擇高水位才洗的乾淨 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000977, 'single', '90009', '如果水龍頭流量過大，下列何種處理方式是錯誤的？', '加裝節水墊片或起 波器,加裝可自動關閉水龍頭的自動感應器,直接換裝沒有省水標章的 水龍頭,直接調整水龍頭到適當水量 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000978, 'single', '90009', '洗菜水、洗碗水、洗衣水、洗澡水等的清洗水，不可直接利用來做什麼用 途？', '洗地板,沖馬桶,澆花,飲用水 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000979, 'single', '90009', '如果馬桶有不正常的漏水問題，下列何者處理方式是錯誤的？', '因為馬桶 還能正常使用，所以不用著急，等到不能用時再報修即可,立刻檢查馬桶 水箱零件有無鬆脫，並確認有無漏水,滴幾滴食用色素到水箱裡，檢查有 無有色水流進馬桶，代表可能有漏水,通知水電行或檢修人員來檢修，徹 底根絕漏水問題 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000980, 'single', '90009', '水費的計量單位是「度」，你知道一度水的容量大約有多少？', '2,000 公 升,3000 個600cc 的寶特瓶,1 立方公尺的水量,3 立方公尺的水量 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000981, 'single', '90009', '臺灣在一年中什麼時期會比較缺水(即枯水期)？', '6 月至9 月,9 月至12 月,11 月至次年4 月,臺灣全年不缺水 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000982, 'single', '90009', '下列何種現象「不是」直接造成台灣缺水的原因？', '降雨季節分佈不平 均，有時候連續好幾個月不下雨，有時又會下起豪大雨,地形山高坡陡， 所以雨一下很快就會流入大海,因為民生與工商業用水需求量都愈來愈 大，所以缺水季節很容易無水可用,台灣地區夏天過熱，致蒸發量過 大 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000983, 'single', '90009', '冷凍食品該如何讓它退冰，才是既「節能」又「省水」？', '直接用水沖食 物強迫退冰,使用微波爐解凍快速又方便,烹煮前盡早拿出來放置退冰,用熱水浸泡，每5 分鐘更換一次 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000984, 'single', '90009', '洗碗、洗菜用何種方式可以達到清洗又省水的效果？', '對著水龍頭直接沖 洗，且要盡量將水龍頭開大才能確保洗的乾淨,將適量的水放在盆槽內洗 濯，以減少用水,把碗盤、菜等浸在水盆裡，再開水龍頭拼命沖水,用 熱水及冷水大量交叉沖洗達到最佳清洗效果 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000985, 'single', '90009', '解決台灣水荒(缺水)問題的無效對策是', '興建水庫、蓄洪(豐)濟枯,全面 節約用水,水資源重複利用，海水淡化…等,積極推動全民體育運動 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000986, 'single', '90009', '如下圖，你知道這是什麼標章嗎？', '奈米標章,環保標章,省水標章,節能標章 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000987, 'single', '90009', '澆花的時間何時較為適當，水分不易蒸發又對植物最好？', '正中午,下 午時段,清晨或傍晚,半夜十二點 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000988, 'single', '90009', '下列何種方式沒有辦法降低洗衣機之使用水量，所以不建議採用？', '使用 低水位清洗,選擇快洗行程,兩、三件衣服也丟洗衣機洗,選擇有自動 調節水量的洗衣機 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000989, 'single', '90009', '有關省水馬桶的使用方式與觀念認知，下列何者是錯誤的？', '選用衛浴設 備時最好能採用省水標章馬桶,如果家裡的馬桶是傳統舊式，可以加裝二 段式沖水配件,省水馬桶因為水量較小，會有沖不乾淨的問題，所以應該 多沖幾次,因為馬桶是家裡用水的大宗，所以應該儘量採用省水馬桶來節 約用水 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000990, 'single', '90009', '下列的洗車方式，何者「無法」節約用水？', '使用有開關的水管可以隨時 控制出水,用水桶及海綿抹布擦洗,用大口徑強力水注沖洗,利用機械 自動洗車，洗車水處理循環使用 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000991, 'single', '90009', '下列何種現象「無法」看出家裡有漏水的問題？', '水龍頭打開使用時，水 表的指針持續在轉動,牆面、地面或天花板忽然出現潮濕的現象,馬桶 裡的水常在晃動，或是沒辦法止水,水費有大幅度增加 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000992, 'single', '90009', '蓮蓬頭出水量過大時，下列對策何者「無法」達到省水？', '換裝有省水標 章的低流量(5~10L/min)蓮蓬頭,淋浴時水量開大，無需改變使用方法,洗澡時間盡量縮短，塗抹肥皂時要把蓮蓬頭關起來,調整熱水器水量到適 中位置 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000993, 'single', '90009', '自來水淨水步驟，何者是錯誤的？', '混凝,沉澱,過濾,煮沸 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000994, 'single', '90009', '為了取得良好的水資源，通常在河川的哪一段興建水庫？', '上游,中游,下游,下游出口 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000995, 'single', '90009', '台灣是屬缺水地區，每人每年實際分配到可利用水量是世界平均值的約多 少？', '1/2,1/4,1/5,1/6 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000996, 'single', '90009', '台灣年降雨量是世界平均值的2.6 倍，卻仍屬缺水地區，下列何者不是真 正缺水的原因？', '台灣由於山坡陡峻，以及颱風豪雨雨勢急促，大部分的 降雨量皆迅速流入海洋,降雨量在地域、季節分佈極不平均,水庫蓋得 太少,台灣自來水水價過於便宜 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000997, 'single', '90009', '電源插座堆積灰塵可能引起電氣意外火災，維護保養時的正確做法是？', '可以先用刷子刷去積塵,直接用吹風機吹開灰塵就可以了,應先關閉電 源總開關箱內控制該插座的分路開關，然後再清理灰塵,可以用金屬接點 清潔劑噴在插座中去除銹蝕 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000998, 'single', '90009', '溫室氣體易造成全球氣候變遷的影響，下列何者不屬於溫室氣體？', '二氧 化碳（CO 2）,氫氟碳化物（HFCs）,甲烷（CH 4）,氧氣（O2） ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000999, 'single', '90009', '就能源管理系統而言，下列何者不是能源效率的表示方式？', '汽車－公里 /公升,照明系統－瓦特/平方公尺(W/m 2),冰水主機－千瓦/冷凍噸 (kW/RT),冰水主機－千瓦 (kW) ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9001000, 'single', '90009', '某工廠規劃汰換老舊低效率設備，以下何種做法並不恰當？', '可考慮使用 較高費用之高效率設備產品,先針對老舊設備建立其「能源指標」或「能 源基線」,唯恐一直浪費能源，馬上將老舊設備汰換掉,改善後需進行 能源績效評估 ', '2', '');